// Coordinator — Phase 3 task 3.2
// Per design plan §2.2. See P-1 (sandbox blocks require) and now P-3
// (sandbox also blocks `require('crypto')`) in .claude/memory/pitfalls.md.
// Uses Node 18+ global `crypto.randomUUID()` (Web Crypto API) — no require.

// ---- filename-regex source_type classifier (design plan §2.3) ----
const CLASSIFIER = [
  { rx: /\b(s-?1|10-?k|10-?q|8-?k|20-?f|prospectus)\b/i, source_type: 'regulatory_filing',  human: 'S-1 Filing' },
  { rx: /\b(press[\s\-_]release|announce(?:ment)?|newswire)\b/i, source_type: 'press_release',     human: 'Press Release' },
  { rx: /\b(teardown|analysis|report|breakdown|case[\s\-_]study)\b/i, source_type: 'analyst_report',    human: 'Analyst Report' },
  { rx: /\b(transcript|call|interview)\b/i,                source_type: 'expert_transcript', human: 'Expert Transcript' },
  { rx: /\b(deck|presentation|pitch|slide)\b/i,            source_type: 'management_deck',   human: 'Management Deck' },
];
function classifyFilename(filename) {
  for (const c of CLASSIFIER) {
    if (c.rx.test(filename)) return { source_type: c.source_type, human: c.human };
  }
  // Fallback (safest default: assume regulatory)
  return { source_type: 'regulatory_filing', human: 'S-1 Filing' };
}

// UUID v4 via Web Crypto API global (Node 18+). No require; sandbox-safe.
function uuidv4() {
  const b = crypto.getRandomValues(new Uint8Array(16));
  b[6] = (b[6] & 0x0f) | 0x40; // version 4
  b[8] = (b[8] & 0x3f) | 0x80; // variant
  const h = Array.from(b, x => x.toString(16).padStart(2, '0')).join('');
  return `${h.slice(0,8)}-${h.slice(8,12)}-${h.slice(12,16)}-${h.slice(16,20)}-${h.slice(20)}`;
}

const item = $input.item.json;

const companyName = item['Company Name'] || item.company_name || 'Unknown Company';
const dealId = companyName.toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');
const runId = uuidv4();
const timestampStarted = new Date().toISOString();

// ---- Build source_manifest from form's Documents metadata array ----
// n8n 2.17.7 Form Trigger emits file metadata on item.Documents (capital D,
// matching the form field label). Shape: [{filename, mimetype, size}, ...].
// Actual binaries are stored by n8n (binaryDataMode=filesystem); passed
// through via binary property for downstream Extract from File nodes.
const uploadedDocs = Array.isArray(item.Documents) ? item.Documents : [];

const humanCounts = {}; // track duplicates for '(#2)' suffix
const documents = uploadedDocs.map((d, idx) => {
  const filename = d.filename || `file-${idx}.pdf`;
  const { source_type, human } = classifyFilename(filename);
  humanCounts[human] = (humanCounts[human] || 0) + 1;
  const suffix = humanCounts[human] > 1 ? ` (#${humanCounts[human]})` : '';
  return {
    file_id: uuidv4(),
    filename,
    source_name: `${companyName} ${human}${suffix}`,
    source_type,
    mime: d.mimetype || 'application/pdf',
    bytes: d.size || 0,
  };
});

const source_manifest = documents.map(d => d.source_name);

if (documents.length < 2) {
  throw new Error(`Need at least 2 documents; received ${documents.length}.`);
}
if (documents.length > 4) {
  throw new Error(`Maximum 4 documents supported; received ${documents.length}.`);
}

return {
  json: {
    run_id: runId,
    deal_id: dealId,
    company_name: companyName,
    timestamp_started: timestampStarted,
    documents,
    source_manifest,
  },
  binary: $input.item.binary, // pass through (may be undefined in fs mode)
};
